sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    const api = new x_neyu_jr_api.JobRelatednessAPI();

    // Extract the JSON body data from the request
    const requestData = request.body.data; 

    var finalResponse = {
        success: false,
        message: "",
        request_number: -1
    };
	var currentStatus = 200;

    try {
        // 1. Check required parameters

        var paramCheck = api.checkForParams(requestData); 
        if (paramCheck.error) {
            finalResponse.message = paramCheck.errorMessage;
			currentStatus = 400;
            response.setStatus(currentStatus);
        } else {
            // 2. Check optional course parameters
            var courseCheck = api.checkOptCourses(requestData);
            if (courseCheck.error) {
                finalResponse.message = courseCheck.errorMessage;
				currentStatus = 400;
                response.setStatus(currentStatus);
            } else {
                // 3. Create record
                var createCheck = api.createRequest(requestData);

                if (createCheck.error) {
                    finalResponse.message = createCheck.errorMessage;
					currentStatus = 400;
                    response.setStatus(currentStatus); 
                } else {
                    finalResponse.success = true;
                    finalResponse.request_number = createCheck.request_number;
                    finalResponse.message = "Record created successfully.";
					currentStatus = 200;
                    response.setStatus(currentStatus);
                }
            }
        }

    } catch (ex) {
        finalResponse.message = "Internal Server Error: " + ex.message;
		currentStatus = 500;
        response.setStatus(currentStatus);
        gs.error("JR_API_EXCEPTION: " + ex.message);
    } finally {
        // SET THE ACTUAL API RESPONSE
        response.setBody(finalResponse);

        // LOG THE RESPONSE FOR AUDITING
        gs.info("JR_API_LOG | Status: {0} | Response: {1}",
            [currentStatus,JSON.stringify(finalResponse)]
        );
    }


})(request, response);
